INSERT INTO public.authored_days (day_id, title, subtitle, status, created_by)
  VALUES (11, 'Jour 11 · Demander son chemin', 'Directions I — à gauche, à droite, tout droit + prépositions de lieu', 'published', NULL);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (11, 10, 'text', $json${"title":"🎯 Objectif du jour","body":"Hoy aprendes a pedir y dar indicaciones básicas en la calle: a la izquierda, a la derecha, todo recto, y las preposiciones de lugar.\n\nAl final del día podrás preguntar cómo llegar a un lugar y entender la respuesta. (Situación: Direcciones · Competencias DELF: CO + PO)"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (11, 20, 'text', $json${"title":"📖 Grammaire — L'impératif de direction + prépositions de lieu","body":"Para dar indicaciones se usa el IMPERATIVO (sin sujeto): Tournez (giren), Allez (vayan), Continuez (continúen), Prenez (tomen).\n\nSe combina con preposiciones de lugar: à gauche (a la izquierda), à droite (a la derecha), tout droit (todo recto), en face de (enfrente de), à côté de (al lado de), près de (cerca de), au bout de (al final de), au coin de (en la esquina de).\n\nFórmula: Tournez à gauche/droite. · Allez tout droit. · C'est en face de / à côté de / près de + lugar.\n\nEjemplos:\n• Tournez à gauche au carrefour. (Giren a la izquierda en el cruce.)\n• Allez tout droit jusqu'au feu. (Vayan todo recto hasta el semáforo.)\n• C'est en face de la pharmacie. (Está enfrente de la farmacia.)\n\n⚠️ Error a evitar: confundir à gauche (izquierda) y à droite (derecha) bajo presión.\n🔊 Pronunciación: tournez [tuʁne] · gauche [ɡoʃ] · droite [dʁwat]"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (11, 30, 'vocab', $json${"items":[{"fr":"à gauche","es":"a la izquierda"},{"fr":"à droite","es":"a la derecha"},{"fr":"tout droit","es":"todo recto"},{"fr":"en face de","es":"enfrente de"},{"fr":"à côté de","es":"al lado de"},{"fr":"près de","es":"cerca de"},{"fr":"loin de","es":"lejos de"},{"fr":"au bout de","es":"al final de"},{"fr":"au coin de","es":"en la esquina de"},{"fr":"entre","es":"entre"},{"fr":"derrière","es":"detrás de"},{"fr":"devant","es":"delante de"},{"fr":"en haut","es":"arriba"},{"fr":"en bas","es":"abajo"},{"fr":"premier étage","es":"primer piso"},{"fr":"deuxième étage","es":"segundo piso"},{"fr":"rez-de-chaussée","es":"planta baja"},{"fr":"un immeuble","es":"un edificio"},{"fr":"un escalier","es":"una escalera"},{"fr":"un ascenseur","es":"un ascensor"},{"fr":"un panneau","es":"un cartel / una señal"},{"fr":"un plan","es":"un plano / mapa"},{"fr":"une impasse","es":"un callejón sin salida"},{"fr":"une place","es":"una plaza"},{"fr":"un quartier","es":"un barrio"},{"fr":"Excusez-moi, je cherche…","es":"Disculpe, busco…"},{"fr":"Pouvez-vous m'indiquer… ?","es":"¿Puede indicarme…?"},{"fr":"Pour aller à…, s'il vous plaît ?","es":"¿Para ir a…, por favor?"},{"fr":"C'est à… minutes à pied.","es":"Está a… minutos a pie."},{"fr":"un bâtiment","es":"un edificio / bloque"}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (11, 40, 'text', $json${"title":"🗝️ Expressions clés","body":"• Excusez-moi, je cherche… — Disculpe, busco…\n• Pour aller à…, s'il vous plaît ? — ¿Para ir a…, por favor?\n• Pouvez-vous m'indiquer… ? — ¿Puede indicarme…?\n• C'est à… minutes à pied. — Está a… minutos a pie.\n• Tournez à gauche. · Allez tout droit. · C'est au bout de la rue."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (11, 50, 'quiz', $json${"questions":[{"q":"«A la izquierda» en francés es…","options":["à droite","à gauche","tout droit"],"correct":1},{"q":"Para decir «giren a la derecha»:","options":["Tournez à droite.","Droite tournez.","Allez à droite le."],"correct":0},{"q":"«Enfrente de la farmacia»:","options":["à côté de la pharmacie","en face de la pharmacie","au bout de la pharmacie"],"correct":1},{"q":"«Todo recto» se dice…","options":["tout droit","tout gauche","au coin"],"correct":0},{"q":"«Está a 5 minutos a pie»:","options":["C'est à 5 minutes à pied.","Il est à 5 minutes pied.","C'est 5 minutes de pied."],"correct":0}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (11, 60, 'writing', $json${"title":"✍️ Production écrite — Indications A → B","prompt":"Écris des indications complètes en français pour aller d'un point A à un point B (utilise l'impératif + prépositions de lieu). Exemple: de la gare à la pharmacie.","example":"Sortez de la gare et tournez à gauche. Allez tout droit jusqu'au carrefour. La pharmacie est en face de la banque, à côté du café."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (11, 70, 'speaking', $json${"title":"🎙️ Production orale — Donne le chemin","prompt":"Enregistre-toi en donnant les indications pour aller de la Place de la République à la gare. Utilise: tournez, allez tout droit, en face de, à côté de.","example":"Depuis la Place de la République, allez tout droit. Prenez la deuxième rue à droite. La gare est au bout de la rue, en face du parc."}$json$::jsonb);

INSERT INTO public.authored_days (day_id, title, subtitle, status, created_by)
  VALUES (12, 'Jour 12 · Lieux de la ville', 'Directions II — pour + infinitif, distances et points de repère', 'published', NULL);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (12, 10, 'text', $json${"title":"🎯 Objectif du jour","body":"Identificar lugares de referencia (gare, mairie, pharmacie, hôpital) y dar indicaciones completas con distancias, usando POUR + infinitivo para expresar el objetivo. (Situación: Direcciones · Competencias DELF: CE + PE)"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (12, 20, 'text', $json${"title":"📖 Grammaire — Pour + infinitif","body":"POUR + infinitivo expresa la finalidad o el objetivo. Se usa mucho para dar indicaciones con un propósito.\n\nFórmula: Pour + infinitif + complément.\n\nEjemplos:\n• Pour aller à la gare, prenez le bus 21. (Para ir a la estación, tome el autobús 21.)\n• Pour trouver la pharmacie, tournez à droite. (Para encontrar la farmacia, gire a la derecha.)\n\n⚠️ Error a evitar: confundir «pour» con «por» — no siempre se traducen igual. Aquí pour = «para».\n🔊 pour [puʁ] · aller [ale]"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (12, 30, 'vocab', $json${"items":[{"fr":"faire demi-tour","es":"dar la vuelta"},{"fr":"un rond-point","es":"una rotonda"},{"fr":"un feu tricolore","es":"un semáforo"},{"fr":"un pont","es":"un puente"},{"fr":"un parking","es":"un aparcamiento"},{"fr":"une gare","es":"una estación de tren"},{"fr":"un aéroport","es":"un aeropuerto"},{"fr":"un hôpital","es":"un hospital"},{"fr":"une mairie","es":"un ayuntamiento"},{"fr":"une école","es":"una escuela"},{"fr":"une université","es":"una universidad"},{"fr":"une église","es":"una iglesia"},{"fr":"un musée","es":"un museo"},{"fr":"un parc","es":"un parque"},{"fr":"un marché","es":"un mercado"},{"fr":"un centre commercial","es":"un centro comercial"},{"fr":"une pharmacie","es":"una farmacia"},{"fr":"un passage souterrain","es":"un paso subterráneo"},{"fr":"une banque","es":"un banco"},{"fr":"la poste","es":"correos"},{"fr":"un hôtel","es":"un hotel"},{"fr":"un appartement","es":"un apartamento"},{"fr":"Continuez tout droit.","es":"Continúe todo recto."},{"fr":"Tournez à gauche / à droite.","es":"Gire a la izquierda / derecha."},{"fr":"Prenez la première / deuxième rue.","es":"Tome la primera / segunda calle."},{"fr":"C'est tout près.","es":"Está muy cerca."},{"fr":"Vous ne pouvez pas le manquer.","es":"No puede perdérselo."},{"fr":"un escalier roulant","es":"una escalera mecánica"},{"fr":"un square","es":"una pequeña plaza"},{"fr":"un jardin","es":"un jardín"}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (12, 40, 'text', $json${"title":"🗝️ Expressions clés","body":"• Pour aller à la gare, s'il vous plaît ? — ¿Para ir a la estación, por favor?\n• Continuez tout droit. · Tournez à gauche après le pont.\n• C'est tout près. · Vous ne pouvez pas le manquer.\n• La gare est à 10 minutes à pied."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (12, 50, 'quiz', $json${"questions":[{"q":"«Para ir a…» se dice:","options":["Pour aller à…","Par aller à…","Pour va à…"],"correct":0},{"q":"«Una estación de tren»:","options":["une gare","une mairie","un pont"],"correct":0},{"q":"«El ayuntamiento»:","options":["la poste","une mairie","une banque"],"correct":1},{"q":"«Continúe todo recto»:","options":["Continuez tout droit.","Continue tout droite.","Tout droit allez."],"correct":0},{"q":"«No puede perdérselo»:","options":["Vous ne pouvez pas le manquer.","Vous ne manquez pas le.","Il ne peut pas manquer."],"correct":0}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (12, 60, 'writing', $json${"title":"✍️ Production écrite — Itinéraire complet","prompt":"Escribe indicaciones completas para llegar de un lugar A a un lugar B usando pour + infinitif y puntos de referencia (gare, pont, feu, rond-point).","example":"Pour aller à l'hôpital, sortez de l'hôtel et allez tout droit. Traversez le pont, puis tournez à droite au feu. L'hôpital est à côté de la mairie."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (12, 70, 'speaking', $json${"title":"🎙️ Production orale — Vers l'hôpital","prompt":"Enregistre-toi en expliquant comment aller à l'hôpital le plus proche depuis l'endroit où tu es. Utilise pour + infinitif.","example":"Pour aller à l'hôpital, prenez la première rue à droite, continuez tout droit et traversez le rond-point. C'est en face du parc."}$json$::jsonb);

INSERT INTO public.authored_days (day_id, title, subtitle, status, created_by)
  VALUES (13, 'Jour 13 · À la pharmacie', 'Pharmacie I — demander un médicament et comprendre la posologie', 'published', NULL);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 10, 'text', $json${"title":"🎯 Objectif du jour","body":"Pedir un medicamento sin receta en la farmacia y entender la posología (cuándo y cómo tomarlo). (Situación: Farmacia · Competencias DELF: CO + PO)"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 20, 'text', $json${"title":"📖 Grammaire — La posologie · Prenez + dose","body":"El farmacéutico te indica la posología (la dosis y el momento). Palabras clave: le matin (por la mañana), le midi (al mediodía), le soir (por la noche), avant le repas (antes de comer), après le repas (después de comer), avec de l'eau (con agua), pendant… jours (durante… días).\n\nEl farmacéutico usa el imperativo: Prenez… (Tome…). Fórmula: Prenez + dose + moment.\n\nEjemplos:\n• Prenez deux comprimés par jour, après le repas. (Tome dos comprimidos al día, después de comer.)\n• Un comprimé le matin et un le soir, pendant 5 jours.\n\nPreguntas útiles: Qu'est-ce que vous me conseillez ? (¿Qué me aconseja?) · C'est sans ordonnance ? (¿Es sin receta?) · C'est remboursé ? (¿Lo cubre el seguro?)\n🔊 ordonnance [ɔʁdɔnɑ̃s] · comprimé [kɔ̃pʁime]"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 30, 'vocab', $json${"items":[{"fr":"la parapharmacie","es":"la parafarmacia"},{"fr":"un pharmacien","es":"un farmacéutico"},{"fr":"un médicament","es":"un medicamento"},{"fr":"une ordonnance","es":"una receta médica"},{"fr":"un comprimé","es":"un comprimido"},{"fr":"une gélule","es":"una cápsula"},{"fr":"un sirop","es":"un jarabe"},{"fr":"une pommade","es":"una pomada"},{"fr":"une crème","es":"una crema"},{"fr":"un spray","es":"un spray"},{"fr":"des gouttes","es":"gotas"},{"fr":"une dose","es":"una dosis"},{"fr":"la posologie","es":"la posología / dosis"},{"fr":"le matin","es":"por la mañana"},{"fr":"le soir","es":"por la noche"},{"fr":"avant le repas","es":"antes de comer"},{"fr":"après le repas","es":"después de comer"},{"fr":"avec de l'eau","es":"con agua"},{"fr":"pendant… jours","es":"durante… días"},{"fr":"un tube","es":"un tubo"},{"fr":"un flacon","es":"un frasco"},{"fr":"être allergique à","es":"ser alérgico/a a"},{"fr":"sans ordonnance","es":"sin receta"},{"fr":"renouveler","es":"renovar"},{"fr":"Qu'est-ce que vous me conseillez ?","es":"¿Qué me aconseja?"},{"fr":"C'est remboursé ?","es":"¿Está cubierto por el seguro?"},{"fr":"une notice","es":"un prospecto"},{"fr":"un effet secondaire","es":"un efecto secundario"},{"fr":"le remboursement","es":"el reembolso"},{"fr":"le midi","es":"al mediodía"}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 40, 'text', $json${"title":"🗝️ Expressions clés","body":"• Vous avez quelque chose pour la toux ? — ¿Tiene algo para la tos?\n• C'est disponible sans ordonnance ? — ¿Está disponible sin receta?\n• Prenez deux comprimés après le repas.\n• Qu'est-ce que vous me conseillez ?"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 50, 'quiz', $json${"questions":[{"q":"«Una receta médica»:","options":["une ordonnance","une posologie","un comprimé"],"correct":0},{"q":"«Tome dos comprimidos»:","options":["Prenez deux comprimés","Prends deux comprimé","Prenez deux comprimé"],"correct":0},{"q":"«Antes de comer»:","options":["après le repas","avant le repas","avec de l'eau"],"correct":1},{"q":"«Sin receta»:","options":["sans ordonnance","sans posologie","sans dose"],"correct":0},{"q":"«¿Qué me aconseja?»:","options":["Qu'est-ce que vous me conseillez ?","Qu'est-ce que vous conseille ?","Que me conseil ?"],"correct":0}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 60, 'writing', $json${"title":"✍️ Production écrite — À la pharmacie","prompt":"Escribe cómo pedirías un medicamento para la tos, sin receta, y pregunta la dosis (2-3 frases en francés).","example":"Bonjour, vous avez quelque chose pour la toux, s'il vous plaît ? Je n'ai pas d'ordonnance. Combien de fois par jour faut-il le prendre ?"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 70, 'speaking', $json${"title":"🎙️ Production orale — Demander un médicament","prompt":"Enregistre-toi en demandant un médicament pour la toux sans ordonnance et en demandant la posologie, comme au comptoir de la pharmacie.","example":"Bonjour, j'ai de la toux depuis deux jours. Qu'est-ce que vous me conseillez sans ordonnance ? Je le prends combien de fois par jour ?"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (13, 80, 'text', $json${"title":"💬 Dialogue modèle","body":"Client : Bonjour, j'ai mal à la gorge et j'ai de la fièvre depuis hier.\nPharmacien : Vous avez une ordonnance ?\nClient : Non, je n'ai pas d'ordonnance.\nPharmacien : D'accord. Prenez ce sirop, deux cuillères trois fois par jour après le repas. Et si la fièvre ne passe pas, il faut voir un médecin.\nClient : C'est remboursé ?\nPharmacien : Non, ce n'est pas sur ordonnance."}$json$::jsonb);

INSERT INTO public.authored_days (day_id, title, subtitle, status, created_by)
  VALUES (14, 'Jour 14 · Décrire ses symptômes', 'Pharmacie II — avoir mal à + partie du corps · il faut + infinitif', 'published', NULL);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (14, 10, 'text', $json${"title":"🎯 Objectif du jour","body":"Describir tus síntomas (avoir mal à + parte del cuerpo), decir desde cuándo y si es urgente. (Situación: Farmacia · Competencias DELF: CO + PE)"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (14, 20, 'text', $json${"title":"📖 Grammaire — Avoir mal à + partie du corps · Il faut + infinitif","body":"Para decir que algo te DUELE se usa AVOIR MAL À. La preposición à se contrae con el artículo:\n• à + la → à la : J'ai mal à la tête / à la gorge.\n• à + le → au : J'ai mal au dos / au ventre.\n• à + les → aux : J'ai mal aux pieds.\n\n⚠️ No se dice «je suis mal à la tête» — se usa AVOIR (j'ai), no être.\n\nPara la necesidad/consejo: IL FAUT + infinitivo (hay que…). Ej.: Il faut voir un médecin. (Hay que ver a un médico.)\n\nDesde cuándo: depuis hier (desde ayer), depuis deux jours, depuis une semaine.\n🔊 j'ai mal [ʒɛ mal] · gorge [ɡɔʁʒ] · fièvre [fjɛvʁ]"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (14, 30, 'vocab', $json${"items":[{"fr":"J'ai mal à la tête.","es":"Me duele la cabeza."},{"fr":"J'ai mal à la gorge.","es":"Me duele la garganta."},{"fr":"J'ai mal au ventre.","es":"Me duele el estómago."},{"fr":"J'ai mal au dos.","es":"Me duele la espalda."},{"fr":"J'ai de la fièvre.","es":"Tengo fiebre."},{"fr":"J'ai un rhume.","es":"Tengo un resfriado."},{"fr":"J'ai la toux.","es":"Tengo tos."},{"fr":"J'ai une douleur.","es":"Tengo un dolor."},{"fr":"J'ai des nausées.","es":"Tengo náuseas."},{"fr":"J'ai des vertiges.","es":"Tengo mareos."},{"fr":"Je me suis coupé(e).","es":"Me corté."},{"fr":"Je me suis brûlé(e).","es":"Me quemé."},{"fr":"Je me suis tordu(e).","es":"Me torcí."},{"fr":"Je saigne.","es":"Estoy sangrando."},{"fr":"Je vomis.","es":"Vomito."},{"fr":"Je tousse.","es":"Tengo tos / toso."},{"fr":"Je suis fatigué(e).","es":"Estoy cansado/a."},{"fr":"Je ne dors pas bien.","es":"No duermo bien."},{"fr":"depuis hier","es":"desde ayer"},{"fr":"depuis deux jours","es":"desde hace dos días"},{"fr":"depuis une semaine","es":"desde hace una semana"},{"fr":"C'est grave ?","es":"¿Es grave?"},{"fr":"urgent","es":"urgente"},{"fr":"Il faut voir un médecin.","es":"Hay que ver a un médico."},{"fr":"Prenez…","es":"Tome…"},{"fr":"Je n'ai pas d'ordonnance.","es":"No tengo receta."},{"fr":"J'ai une blessure.","es":"Tengo una herida."},{"fr":"chronique","es":"crónico"},{"fr":"légèrement","es":"ligeramente"},{"fr":"aigu","es":"agudo"}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (14, 40, 'text', $json${"title":"🗝️ Expressions clés","body":"• J'ai mal à la tête depuis hier. — Me duele la cabeza desde ayer.\n• J'ai de la fièvre. · J'ai un rhume.\n• C'est grave ? — ¿Es grave?\n• Il faut voir un médecin. — Hay que ver a un médico."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (14, 50, 'quiz', $json${"questions":[{"q":"«Me duele la cabeza»:","options":["J'ai mal à la tête.","Je suis mal à la tête.","J'ai mal au tête."],"correct":0},{"q":"«Me duele la espalda» (le dos):","options":["J'ai mal à le dos.","J'ai mal au dos.","J'ai mal dos."],"correct":1},{"q":"«Desde hace dos días»:","options":["depuis deux jours","pendant deux jours","il y a deux jours"],"correct":0},{"q":"«Hay que ver a un médico»:","options":["Il faut voir un médecin.","Il faut que voir un médecin.","Il faut voir médecin."],"correct":0},{"q":"«Tengo fiebre»:","options":["J'ai de la fièvre.","Je suis fièvre.","J'ai fièvre."],"correct":0}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (14, 60, 'writing', $json${"title":"✍️ Production écrite — Mes symptômes","prompt":"Escribe 5 frases describiendo síntomas diferentes con avoir mal à + parte del cuerpo, e indica desde cuándo los tienes.","example":"J'ai mal à la tête depuis ce matin. J'ai mal à la gorge depuis hier. J'ai de la fièvre depuis deux jours. J'ai mal au ventre après le repas. Je tousse depuis une semaine."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (14, 70, 'speaking', $json${"title":"🎙️ Production orale — Chez le pharmacien","prompt":"Enregistre-toi en décrivant 3 symptômes (avoir mal à…), dis depuis quand et demande si c'est grave.","example":"Bonjour, j'ai mal à la gorge et j'ai de la fièvre depuis hier. J'ai aussi mal à la tête. C'est grave, docteur ?"}$json$::jsonb);

INSERT INTO public.authored_days (day_id, title, subtitle, status, created_by)
  VALUES (15, 'Jour 15 · Dans la boutique', 'Vêtements I — tailles, couleurs et comparatifs (plus / moins / aussi… que)', 'published', NULL);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (15, 10, 'text', $json${"title":"🎯 Objectif du jour","body":"Pedir tallas y colores, preguntar disponibilidad y pedir para probarte una prenda. Comparar prendas con plus / moins / aussi… que. (Situación: Tienda de ropa · Competencias DELF: CO + PO)"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (15, 20, 'text', $json${"title":"📖 Grammaire — Les comparatifs : plus / moins / aussi + adjectif + que","body":"Para comparar en francés:\n• plus + adjetivo + que = más… que → Cette robe est plus belle que l'autre.\n• moins + adjetivo + que = menos… que → Ce pull est moins cher que la veste.\n• aussi + adjetivo + que = tan… como → Il est aussi confortable que l'autre.\n\nEl adjetivo concuerda en género y número: plus belle (fem.), plus grand (masc.).\n\nPara pedir en la tienda: Vous avez ça en… ? (¿Lo tiene en…?) · Je peux l'essayer ? (¿Puedo probármelo?)\n🔊 plus [ply] · moins [mwɛ̃] · aussi [osi]"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (15, 30, 'vocab', $json${"items":[{"fr":"un vêtement","es":"una prenda de ropa"},{"fr":"une robe","es":"un vestido"},{"fr":"une jupe","es":"una falda"},{"fr":"un pantalon","es":"un pantalón"},{"fr":"un jean","es":"unos vaqueros"},{"fr":"une chemise","es":"una camisa"},{"fr":"un chemisier","es":"una blusa"},{"fr":"un t-shirt","es":"una camiseta"},{"fr":"un pull","es":"un jersey / suéter"},{"fr":"une veste","es":"una chaqueta"},{"fr":"un manteau","es":"un abrigo"},{"fr":"des chaussures","es":"zapatos"},{"fr":"des baskets","es":"zapatillas deportivas"},{"fr":"des bottes","es":"botas"},{"fr":"des sandales","es":"sandalias"},{"fr":"un maillot de bain","es":"un traje de baño"},{"fr":"une écharpe","es":"una bufanda"},{"fr":"la taille","es":"la talla"},{"fr":"la pointure","es":"el número (zapatos)"},{"fr":"XS / S / M / L / XL","es":"tallas de ropa"},{"fr":"une couleur","es":"un color"},{"fr":"des rayures","es":"rayas"},{"fr":"uni","es":"liso (sin estampado)"},{"fr":"Vous avez ça en… ?","es":"¿Lo tiene en…?"},{"fr":"Je peux l'essayer ?","es":"¿Puedo probármelo?"},{"fr":"un short","es":"un pantalón corto"},{"fr":"une ceinture","es":"un cinturón"},{"fr":"un chapeau","es":"un sombrero"},{"fr":"des lunettes","es":"gafas"},{"fr":"un motif","es":"un estampado"}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (15, 40, 'text', $json${"title":"🗝️ Expressions clés","body":"• Je voudrais essayer cette robe. — Quisiera probarme este vestido.\n• Vous avez ça en rouge ? · Je peux l'essayer ?\n• Quelle est votre taille ? / votre pointure ?\n• C'est plus grand / moins cher / aussi confortable que l'autre."}$json$::jsonb);
