  VALUES (15, 50, 'quiz', $json${"questions":[{"q":"«Un vestido»:","options":["une jupe","une robe","une veste"],"correct":1},{"q":"«¿Puedo probármelo?»:","options":["Je peux l'essayer ?","Je peux essayer le ?","Je peux le essaie ?"],"correct":0},{"q":"«Más barato que»:","options":["plus cher que","moins cher que","aussi cher que"],"correct":1},{"q":"«La talla» (de ropa):","options":["la pointure","la taille","le motif"],"correct":1},{"q":"«¿Lo tiene en rojo?»:","options":["Vous avez ça en rouge ?","Vous avez ça rouge ?","Avez ça en rouge ?"],"correct":0}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (15, 60, 'writing', $json${"title":"✍️ Production écrite — Comparer deux vêtements","prompt":"Escribe 4 frases comparando dos prendas (precio, talla, color, material) usando plus / moins / aussi… que.","example":"La robe rouge est plus belle que la robe noire. Le pull bleu est moins cher que la veste. Ce t-shirt est aussi confortable que l'autre. Le manteau gris est plus chaud que la veste."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (15, 70, 'speaking', $json${"title":"🎙️ Production orale — Essayer des vêtements","prompt":"Enregistre-toi en demandant d'essayer 2 vêtements différents avec la taille et la couleur, puis compare-les.","example":"Bonjour, je voudrais essayer cette chemise blanche en taille M et ce pull bleu en L. Le pull est plus chaud, mais la chemise est plus élégante."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (15, 80, 'text', $json${"title":"💬 Dialogue modèle","body":"Vendeur : Bonjour, je peux vous aider ?\nClient : Oui, je voudrais essayer cette robe en taille M, s'il vous plaît.\nVendeur : Bien sûr, les cabines sont au fond.\n[…]\nClient : C'est trop petit. Vous avez en L ?\nVendeur : Voilà, en L. Celle-ci est aussi moins chère.\nClient : Parfait, ça me va très bien. Je la prends !"}$json$::jsonb);

COMMIT;
